+      ? (metadata as Record<string, unknown>).clawdis
+      : undefined
+  const clawdisRaw = clawdisFromMetadata ?? frontmatter.clawdis
+  if (!clawdisRaw || typeof clawdisRaw !== 'object' || Array.isArray(clawdisRaw)) return undefined
